### Creating Custom Pipes

Use the `@Pipe` decorator and implement the `PipeTransform` interface:

```typescript
import { Pipe, PipeTransform } from '@angular/core';

@Pipe({
  name: 'truncate',
  standalone: true
})
export class TruncatePipe implements PipeTransform {
  transform(value: string, maxLength: number = 50, ellipsis: string = '...'): string {
    if (!value) return '';
    return value.length > maxLength
      ? value.substring(0, maxLength) + ellipsis
      : value;
  }
}
```

### Usage

```html
<p>{{ longText | truncate:100:'...' }}</p>
<p>{{ longText | truncate:50 }}</p>
<p>{{ longText | truncate }}</p>
```

### Pipe with Multiple Parameters

```typescript
@Pipe({ name: 'sort', standalone: true })
export class SortPipe implements PipeTransform {
  transform<T>(array: T[], field: keyof T, order: 'asc' | 'desc' = 'asc'): T[] {
    if (!array || !array.length) return [];
    return [...array].sort((a, b) => {
      const aVal = a[field];
      const bVal = b[field];
      if (aVal < bVal) return order === 'asc' ? -1 : 1;
      if (aVal > bVal) return order === 'asc' ? 1 : -1;
      return 0;
    });
  }
}
```

### Pure vs Impure Pipes

**Pure pipes (default)** — Only re-evaluated when the input value changes by reference. Angular uses a pure function approach for performance.

**Impure pipes** — Re-evaluated on every change detection cycle. Set `pure: false`:

```typescript
@Pipe({
  name: 'filter',
  pure: false  // Impure — runs on every change detection
})
export class FilterPipe implements PipeTransform {
  transform(items: any[], searchText: string): any[] {
    if (!items) return [];
    if (!searchText) return items;
    return items.filter(item =>
      JSON.stringify(item).toLowerCase().includes(searchText.toLowerCase())
    );
  }
}
```

**Warning:** Impure pipes can cause performance issues because they execute frequently. Use them sparingly or consider alternative approaches like computed properties.

### Registering Custom Pipes

```typescript
// With NgModule
@NgModule({
  declarations: [TruncatePipe],
  exports: [TruncatePipe]
})

// Standalone
@Component({
  imports: [TruncatePipe]
})
```

codeExample:
@Pipe({ name: 'exponentialStrength', standalone: true })
export class ExponentialStrengthPipe implements PipeTransform {
  transform(value: number, exponent: number = 1): number {
    return Math.pow(value, exponent);
  }
}

// Usage: {{ 2 | exponentialStrength:10 }} => 1024
